// Initial Implementation

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  try {
    const url = new URL(request.url);
    if (url.pathname === '/send-email') {
      return await sendEmail(request);
    } else if (url.pathname === '/process-payment') {
      return await processPayment(request);
    }
  } catch (error) {
    console.error(error);
    return new Response('Internal Server Error', { status: 500 });
  }
}

async function sendEmail(request) {
  const apiKey = 'YOUR_SENDGRID_API_KEY';
  const apiSecret = 'YOUR_SENDGRID_API_SECRET';
  const emailBody = await request.text();
  const response = await fetch(`https://api.sendgrid.com/v3/mail/send`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      personalizations: [
        {
          to: [{ email: 'recipient@example.com' }]
        }
      ],
      from: { email: 'sender@example.com' },
      subject: 'Test Email',
      content: [
        {
          type: 'text/plain',
          value: emailBody
        }
      ]
    })
  });
  return response;
}

async function processPayment(request) {
  const apiKey = 'YOUR_STRIPE_API_KEY';
  const apiSecret = 'YOUR_STRIPE_API_SECRET';
  const paymentMethod = await request.json();
  const response = await fetch(`https://api.stripe.com/v1/charges`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      amount: 1000,
      currency: 'usd',
      source: paymentMethod
    })
  });
  return response;
}